#include<bits/stdc++.h>
#define LL long long
#define fr first
#define se second
#define pb push_back
using namespace std;
const int N = 2e5+5;
LL n,a[N],sum,f[N],Cnt;
vector<int> g[N];
void DFS(int u,int fa){
    for(int v:g[u])if(v^fa)DFS(v,u);
    f[u]=a[u]-sum,a[fa]+=f[u];if(f[u]!=0)Cnt++;return;
}
void Solve(int u,int fa){
    for(int v:g[u])if(v^fa&&f[v]>=0)Solve(v,u);
    for(int v:g[u])if(v^fa&&f[v]<0)
        {cout<<u<<" "<<v<<" "<<-f[v]<<"\n";Solve(v,u);}
    if(f[u]>0)cout<<u<<" "<<fa<<" "<<f[u]<<"\n";return;
}
int main(){
    //freopen("tree.in","r",stdin);
    //freopen("tree.out","w",stdout);
    cin>>n;
    for(int i=1;i<=n;i++){cin>>a[i];sum+=a[i];}sum/=n;
    for(int i=1;i<n;i++){int x,y;cin>>x>>y;g[x].pb(y),g[y].pb(x);}
    DFS(1,0);cout<<Cnt<<"\n";Solve(1,0);
    return 0;
}
